import{_ as t,c as i,o as r,aq as a}from"./chunks/framework.jeRwkH3J.js";const g=JSON.parse('{"title":"Contribute","description":"Find out how to help translate or build the app and external plugins.","frontmatter":{"title":"Contribute","description":"Find out how to help translate or build the app and external plugins.","footer":false},"headers":[],"relativePath":"dev/contribute/index.md","filePath":"dev/contribute/index.md","lastUpdated":1777441787000,"breadcrumbs":[{"text":"For developers","items":[{"text":"Contribute","link":"/dev/contribute/"},{"text":"Plugin package format","link":"/dev/parsers-library/"},{"text":"Synchronization server","link":"/dev/sync-server/"},{"text":"External plugins SDK","link":"/dev/plugin-sdk/"}]},{"text":"Contribute","link":"/dev/contribute/"}]}'),n={name:"dev/contribute/index.md"};function o(s,e,l,u,d,p){return r(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="contribute" tabindex="-1">Contribute <a class="header-anchor" href="#contribute" aria-label="Permalink to &quot;Contribute&quot;">​</a></h1><p>Find out how to help translate or build the app and external plugins.</p><h2 id="app-contribution-guidelines" tabindex="-1">App contribution guidelines <a class="header-anchor" href="#app-contribution-guidelines" aria-label="Permalink to &quot;App contribution guidelines&quot;">​</a></h2><ul><li>If you want to fix bug or implement a new feature already listed in <a href="https://github.com/UsagiApp/Usagi/issues" target="_blank" rel="noreferrer">issues</a>, assign the issue to yourself and/or comment first.</li><li>For major features, open an issue or discussion first to confirm scope and direction.</li><li>Translations have to be managed using the <a href="https://hosted.weblate.org/engage/usagi/" target="_blank" rel="noreferrer">Weblate</a> platform.</li><li>Online sources are loaded through external plugins, not bundled directly in the app.</li></ul><p>Refactoring and developer-experience improvements are welcome. Please keep these principles in mind:</p><ul><li>Performance matters. In the case of choosing between source code beauty and performance, performance should be a priority.</li><li>Please do not modify README and other information files unless necessary (except typos).</li><li>Avoid adding new dependencies unless required. APK size is important.</li></ul><h2 id="external-plugin-contribution" tabindex="-1">External plugin contribution guidelines <a class="header-anchor" href="#external-plugin-contribution" aria-label="Permalink to &quot;External plugin contribution guidelines&quot;">​</a></h2><p>Usagi loads source providers from external <code>.jar</code> plugins.</p><h3 id="distribution-requirements" tabindex="-1">Distribution requirements <a class="header-anchor" href="#distribution-requirements" aria-label="Permalink to &quot;Distribution requirements&quot;">​</a></h3><ul><li>Package your plugin as a <code>.jar</code> file.</li><li>To support <strong>Import from GitHub</strong>, publish the <code>.jar</code> asset in the repository&#39;s latest release.</li><li>Keep source keys stable between releases to avoid breaking user data.</li><li>Test compatibility against the current Usagi release before publishing.</li></ul><h3 id="testing-flow-in-usagi" tabindex="-1">Testing flow in Usagi <a class="header-anchor" href="#testing-flow-in-usagi" aria-label="Permalink to &quot;Testing flow in Usagi&quot;">​</a></h3><ol><li>Open <strong>Settings</strong> -&gt; <strong>Sources</strong> -&gt; <strong>Manage plugins</strong>.</li><li>Import your plugin via GitHub repository or local <code>.jar</code>.</li><li>Verify that the plugin loads successfully.</li><li>Open <strong>Sources Catalog</strong> and confirm that your sources appear and can be enabled.</li><li>Validate browse/search/details/chapters/pages before release.</li></ol><p>For implementation details, see <a href="/dev/plugin-sdk/">External plugins SDK</a>.</p><h2 id="help" tabindex="-1">Help <a class="header-anchor" href="#help" aria-label="Permalink to &quot;Help&quot;">​</a></h2><p>If you need help or have some questions, ask a community in our <a href="https://t.me/UsagiApp" target="_blank" rel="noreferrer">Telegram chat</a> or <a href="https://discord.gg/4AHskjwtj4" target="_blank" rel="noreferrer">Discord server</a>.</p>',15)])])}const h=t(n,[["render",o]]);export{g as __pageData,h as default};
